proof fn phi_1_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_2_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    assert forall |i: nat| #[trigger] (ex.suffix(0).nat_to_state)(i) == (ex.nat_to_state)(i) by {
        assert((ex.suffix(0).nat_to_state)(i) == (ex.nat_to_state)(i + 0));
    };
    execution_equality::<int>(ex.suffix(0), ex);
}

proof fn phi_3_suffix_composition_equals_addition(ex: Execution<int>, a: nat, b: nat)
    ensures
        ex.suffix(a).suffix(b) == ex.suffix(a + b),
{
    assert forall |i: nat| #[trigger] (ex.suffix(a).suffix(b).nat_to_state)(i) == (ex.suffix(a + b).nat_to_state)(i) by {
        assert((ex.suffix(a).suffix(b).nat_to_state)(i) == (ex.nat_to_state)(i + b + a));
        assert((ex.suffix(a + b).nat_to_state)(i) == (ex.nat_to_state)(i + (a + b)));
    };
    execution_equality::<int>(ex.suffix(a).suffix(b), ex.suffix(a + b));
}

proof fn phi_4_eventually_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        p.satisfied_by(ex.suffix(i)),
    ensures
        eventually(p).satisfied_by(ex),
{
    eventually_unfold::<int>(ex, p);
}

proof fn phi_5_eventually_propagate_to_zero(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        p.satisfied_by(ex.suffix(i)),
    ensures
        eventually(p).satisfied_by(ex),
{
    assert(eventually(p).satisfied_by(ex.suffix(0))) by {
        assert(p.satisfied_by(ex.suffix(0).suffix(i)));
        execution_equality::<int>(ex.suffix(0).suffix(i), ex.suffix(i));
    };
    execution_equality::<int>(ex.suffix(0), ex);
}
